-- source: V28__saving_app_store_mapping_paywall_ab_history_pro.sql
-- saving App Store 字段映射、Paywall AB 策略与本机历史报告 Pro 增强。
-- 中文说明：本迁移只配置审核材料、转化文案与本机报告历史展示策略；不新增用户数据服务端存储，不开启云同步。

UPDATE public.sys_remote_config
SET status = 'inactive', updated_at = now()
WHERE app_code = 'saving'
  AND namespace_code IN (
    'saving_app_store_connect_field_mapping',
    'saving_paywall_ab_policy',
    'saving_report_history_pro_policy'
  );

