-- source: V35__sys_entitlement_center_mode3.sql
-- 统一后台式权益中心（模式三：老用户权益保护版）。
-- 中文说明：统一后端同时承载拍拍伴读、saving、FitMystery 等多个 App，权益配置必须按 app_code 隔离。
-- 设计目标：
-- 1) 免费权益按当前后台配置动态调整；
-- 2) 付费权益在有效期内保留购买时快照，后台降配不能影响已付款承诺；
-- 3) 新增/提升权益自动给有效期内老用户补齐；
-- 4) 人工赠送和用户级覆盖不要写 sys_entitlement_snapshot，避免被 App Store 刷新覆盖。

CREATE TABLE IF NOT EXISTS public.sys_membership_plan (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    app_code varchar(64) NOT NULL,
    plan_code varchar(64) NOT NULL,
    display_name varchar(128) NOT NULL,
    description varchar(512),
    plan_level integer DEFAULT 0 NOT NULL,
    entitlement_code varchar(64),
    status varchar(32) DEFAULT 'active' NOT NULL,
    sort_order integer DEFAULT 0 NOT NULL,
    metadata_json jsonb,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE UNIQUE INDEX IF NOT EXISTS uk_sys_membership_plan_app_plan ON public.sys_membership_plan(app_code, plan_code);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE INDEX IF NOT EXISTS idx_sys_membership_plan_app_status ON public.sys_membership_plan(app_code, status);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE TABLE IF NOT EXISTS public.sys_entitlement_feature (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    app_code varchar(64) NOT NULL,
    feature_code varchar(96) NOT NULL,
    feature_name varchar(128) NOT NULL,
    feature_type varchar(32) DEFAULT 'boolean' NOT NULL,
    description varchar(512),
    default_enabled boolean DEFAULT false NOT NULL,
    backend_enforced boolean DEFAULT false NOT NULL,
    frontend_visible boolean DEFAULT true NOT NULL,
    status varchar(32) DEFAULT 'active' NOT NULL,
    metadata_json jsonb,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE UNIQUE INDEX IF NOT EXISTS uk_sys_entitlement_feature_app_feature ON public.sys_entitlement_feature(app_code, feature_code);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE INDEX IF NOT EXISTS idx_sys_entitlement_feature_app_status ON public.sys_entitlement_feature(app_code, status);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE TABLE IF NOT EXISTS public.sys_plan_feature_rule (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    app_code varchar(64) NOT NULL,
    plan_code varchar(64) NOT NULL,
    feature_code varchar(96) NOT NULL,
    enabled boolean DEFAULT false NOT NULL,
    access_level varchar(32) DEFAULT 'none' NOT NULL,
    limit_value integer,
    limit_unit varchar(32),
    scope_code varchar(64),
    priority integer DEFAULT 0 NOT NULL,
    effective_start_at timestamp with time zone,
    effective_end_at timestamp with time zone,
    status varchar(32) DEFAULT 'active' NOT NULL,
    rule_json jsonb,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL
);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE UNIQUE INDEX IF NOT EXISTS uk_sys_plan_feature_rule_app_plan_feature ON public.sys_plan_feature_rule(app_code, plan_code, feature_code);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE INDEX IF NOT EXISTS idx_sys_plan_feature_rule_app_plan ON public.sys_plan_feature_rule(app_code, plan_code, status);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE INDEX IF NOT EXISTS idx_sys_plan_feature_rule_app_feature ON public.sys_plan_feature_rule(app_code, feature_code, status);

-- source: V35__sys_entitlement_center_mode3.sql
CREATE TABLE IF NOT EXISTS public.sys_product_entitlement_mapping (
    id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    app_code varchar(64) NOT NULL,
    store_code varchar(32) DEFAULT 'appstore' NOT NULL,
    product_id varchar(128) NOT NULL,
    plan_code varchar(64),
